#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int N, M, K;
    cin >> N >> M >> K;
    vector<vector<pair<int,int>>> adj(N + 1);
    for (int i = 0; i < M; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        adj[u].push_back({v, w});
    }
    // 각 정점마다 최단 K개의 거리를 저장하는 최대 힙
    vector<priority_queue<long long>> best(N + 1);
    priority_queue<pair<long long,int>, vector<pair<long long,int>>, greater<pair<long long,int>>> pq;
    pq.push({0, 1});
    best[1].push(0);
    while (!pq.empty()) {
        auto [d, u] = pq.top(); pq.pop();
        // u까지의 거리가 이미 K개 확정되고 d가 그보다 크면 무시
        if ((int)best[u].size() > K) continue;
        // d가 u의 K번째 최단보다 크면 의미 없음 (정확성을 위해 진행 시 검사)
        for (auto [v, w] : adj[u]) {
            long long nd = d + w;
            if ((int)best[v].size() < K) {
                best[v].push(nd);
                pq.push({nd, v});
            } else if (best[v].top() > nd) {
                best[v].pop();
                best[v].push(nd);
                pq.push({nd, v});
            }
        }
    }
    if ((int)best[N].size() < K) cout << -1 << "\n";
    else cout << best[N].top() << "\n";
    return 0;
}
